return await space.current.patchWidget("snake-game", source => {
  const s = String(source)

  const replacements = [
    [
      /const\s+CELL_SIZE\s*=\s*([0-9]+)\s*;?/,
      (m, n) => `const CELL_SIZE = ${n};\nconst MOVE_ANIM_MS = 120;`
    ]
  ]

  let out = s
  for (const [re, fn] of replacements) out = out.replace(re, fn)

  if (!/MOVE_ANIM_MS/.test(out)) {
    out = out.replace(/(const\s+CELL_SIZE\s*=\s*[0-9]+\s*;?\s*)/, `$1\nconst MOVE_ANIM_MS = 120;\n`)
  }

  if (/requestAnimationFrame\s*\(/.test(out) && /transform\s*=/.test(out)) return out

  out = out.replace(
    /class\s+SnakeGame\s*{[\s\S]*?render\(\)\s*{[\s\S]*?}\s*$/m,
    match => {
      const renderStart = match.indexOf('render()')
      return match
    }
  )

  if (!/this\.segmentOffsets/.test(out)) {
    out = out.replace(
      /(constructor\s*\([^)]*\)\s*{[\s\S]*?this\.snake\s*=\s*\[[\s\S]*?\];)/,
      `$1\n    this.segmentOffsets = this.snake.map(() => ({ x: 0, y: 0 }));\n    this.animating = false;\n    this.animStart = 0;\n    this.animFrom = null;\n    this.animTo = null;`
    )
  }

  if (/moveSnake\s*\(\)\s*{/.test(out) && !/animateSnakeMove/.test(out)) {
    out = out.replace(
      /moveSnake\s*\(\)\s*{[\s\S]*?}\n\s*draw\(/,
      `moveSnake() {\n    const head = this.snake[0]\n    const next = { x: head.x + this.dir.x, y: head.y + this.dir.y }\n    if (this.isCollision(next)) return\n\n    this.animating = true\n    this.animStart = performance.now()\n    this.animFrom = this.snake.map(p => ({ x: p.x, y: p.y }))\n    this.animTo = [next, ...this.snake.slice(0, -1).map(p => ({ x: p.x, y: p.y }))]\n\n    const step = (now) => {\n      const t = Math.min(1, (now - this.animStart) / MOVE_ANIM_MS)\n      const eased = t * (2 - t)\n      this.animT = eased\n      if (t < 1) {\n        requestAnimationFrame(step)\n        return\n      }\n      this.snake = this.animTo\n      this.animating = false\n      this.animFrom = null\n      this.animTo = null\n      this.animT = 1\n    }\n    requestAnimationFrame(step)\n  }\n\n  draw(`
    )
  }

  if (/draw\(ctx\)\s*{/.test(out) && !/interpolate/.test(out)) {
    out = out.replace(
      /draw\(ctx\)\s*{([\s\S]*?)}\n\s*}/,
      (m, body) => `draw(ctx) {${body.replace(/this\.snake\.forEach\(\(segment, i\) => \{[\s\S]*?\}\)/, `
    const renderSnake = (segments, offsets = null) => {
      segments.forEach((segment, i) => {
        const off = offsets?.[i] || { x: 0, y: 0 }
        const x = (segment.x + off.x) * CELL_SIZE
        const y = (segment.y + off.y) * CELL_SIZE
        ctx.fillStyle = i === 0 ? '#2ecc71' : '#27ae60'
        ctx.beginPath()
        ctx.roundRect(x + 2, y + 2, CELL_SIZE - 4, CELL_SIZE - 4, 8)
        ctx.fill()
      })
    }

    if (this.animating && this.animFrom && this.animTo) {
      const dx = this.animTo[0].x - this.animFrom[0].x
      const dy = this.animTo[0].y - this.animFrom[0].y
      const animated = this.animFrom.map((seg, i) => ({
        x: seg.x + (this.animTo[i].x - seg.x) * this.animT,
        y: seg.y + (this.animTo[i].y - seg.y) * this.animT
      }))
      renderSnake(animated)
    } else {
      renderSnake(this.snake)
    }`)}`
    )
  }

  return out
})

